/* Restrict the shared library's dynamic exports to the public m2k_*
 * API. Internal symbols — in particular the flex-generated lexer's
 * yylex/yyrestart/yyin family — otherwise collide with a host
 * application's own lexer under ELF symbol interposition: dosemu2's
 * config lexer captured our cmdLex()'s yylex calls, making every AT
 * command silently return CMDST_NOAT. */
{
  global:
    m2k_*;
  local:
    *;
};
